		"bead_id":     beadID,
		"reason":      reason,
		"detail":      detail,
		"fingerprint": fingerprint,
	}, at, threshold)
	if !escalated {
		return false
	}
	detailText := fmt.Sprintf(
		"pre-claim warn fingerprint repeated %d times across %d distinct bead IDs",
		snapshot.Count,
		len(snapshot.DistinctBeadIDs),
	)
	payload := map[string]any{
		"reason":            "preclaim_warn_repeated",
		"detail":            detailText,
